      ) : (
        <input id={id} type="text" value={value} onChange={e => onChange(e.target.value)}
          className="w-full rounded-lg border border-gray-700 bg-gray-800 px-3 py-2 text-sm text-white outline-none focus:border-green-500" />
      )}
    </div>
  )
}

function ContentEditor() {
  const { authed } = useAdminAuth()
  const [section, setSection] = useState("general")
  const [data, setData] = useState<any>({})
  const [saving, setSaving] = useState(false)
  const [saved, setSaved] = useState(false)

  useEffect(() => {
    if (!authed) return
    fetch("/api/admin/content").then(r => r.json()).then(d => { if (d) setData(d) })
  }, [authed])

  const save = async () => {
    setSaving(true)
    const res = await fetch("/api/admin/content", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(data),
    })
    if (res.ok) { setSaved(true); setTimeout(() => setSaved(false), 2000) }
    setSaving(false)
  }

  const set = (path: string, value: any) => {
    const parts = path.split(".")
    let obj = { ...data }
    let cur = obj
    for (let i = 0; i < parts.length - 1; i++) {
      if (!cur[parts[i]]) cur[parts[i]] = {}
      cur[parts[i]] = { ...cur[parts[i]] }
      cur = cur[parts[i]]
    }
    cur[parts[parts.length - 1]] = value
    setData(obj)
  }

  const get = (path: string) => {
    const parts = path.split(".")
    let cur = data
    for (const p of parts) {
      if (cur?.[p] === undefined) return ""
      cur = cur[p]
    }
    return typeof cur === "string" ? cur : ""
  }

  const addItem = (path: string, item: any) => {
    const parts = path.split(".")
    let cur = { ...data }
    let obj = cur
    for (let i = 0; i < parts.length - 1; i++) {
      obj = obj[parts[i]]
    }
    const arr = [...(obj[parts[parts.length - 1]] || []), item]
    obj[parts[parts.length - 1]] = arr
    setData(cur)
  }

  const removeItem = (path: string, index: number) => {
    const parts = path.split(".")
    let cur = { ...data }
    let obj = cur
    for (let i = 0; i < parts.length - 1; i++) {
      obj = obj[parts[i]]
    }
    obj[parts[parts.length - 1]] = obj[parts[parts.length - 1]].filter((_: any, i: number) => i !== index)
