            <input value={form.author} onChange={e => setForm({...form, author: e.target.value})} placeholder="Autor" className="rounded bg-gray-800 border border-gray-700 px-3 py-2 text-sm text-white" />
            <input type="date" value={form.created_at} onChange={e => setForm({...form, created_at: e.target.value})} className="rounded bg-gray-800 border border-gray-700 px-3 py-2 text-sm text-white" />
          </div>
          <input value={form.image_url} onChange={e => setForm({...form, image_url: e.target.value})} placeholder="URL de imagen (opcional)" className="w-full rounded bg-gray-800 border border-gray-700 px-3 py-2 text-sm text-white" />
          <textarea value={form.excerpt} onChange={e => setForm({...form, excerpt: e.target.value})} placeholder="Extracto (breve descripción para la tarjeta)" rows={2} className="w-full rounded bg-gray-800 border border-gray-700 px-3 py-2 text-sm text-white" />
