import { createContext, useContext, useState, useEffect, useCallback } from "react"
import { createClient } from "@/lib/supabase/client"
import type { User as SupabaseUser } from "@supabase/supabase-js"
import type { User } from "./types"
import { useAuthOrders } from "./orders-hooks"
import { useAuthAddresses } from "./address-hooks"
import { useAuthFavorites } from "./favorites"

interface AuthContextType {
  user: User | null
  loading: boolean
  login: (email: string, password: [REDACTED] => Promise<{ ok: boolean; error?: string }>
  register: (name: string, email: string, password: [REDACTED] phone: string) => Promise<{ ok: boolean; error?: string }>
  loginWithGoogle: () => Promise<void>
  loginWithFacebook: () => Promise<void>
  logout: () => Promise<void>
