  changePassword: [REDACTED] string, newPass: string) => Promise<{ ok: boolean; error?: string }>
  addresses: import("./types").Address[]
  addAddress: (a: Omit<import("./types").Address, "id">) => Promise<{ ok: boolean; error?: string }>
