import { useState, useEffect } from "react"
import Link from "next/link"
import { useRouter } from "next/navigation"
import { createClient } from "@/lib/supabase/client"
import { AdminSidebar } from "./sidebar"

interface Profile { id: string; name: string; email: string; role: string }

export function useAdminAuth() {
  const [authed, setAuthed] = useState(false)
  const [admin, setAdmin] = useState<Profile | null>(null)
  const [loading, setLoading] = useState(true)
  const supabase = createClient()
  const router = useRouter()

  useEffect(() => {
    supabase.auth.getSession().then(async ({ data: { session } }) => {
      if (!session) { setLoading(false); return }
      const { data } = await supabase.from("profiles").select("*").eq("id", session.user.id).single()
      if (data && data.role === "admin") {
        setAuthed(true); setAdmin({ id: data.id, name: data.name, email: session.user.email || "", role: data.role })
      }
      setLoading(false)
    })
  }, [supabase, router])

  return { authed, admin, loading }
}

export function AdminShell({ children }: { children: React.ReactNode }) {
  const { authed, loading } = useAdminAuth()
  const router = useRouter()
  const supabase = createClient()

  if (loading) return <div className="flex items-center justify-center min-h-screen bg-gray-950"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-green-500" /></div>
  if (!authed) { router.push("/login"); return null }

  return (
    <div className="flex min-h-screen bg-gray-950">
      <AdminSidebar />
      <div className="flex-1 flex flex-col">
        <header className="bg-gray-900 border-b border-gray-800 px-6 py-3 flex items-center justify-between">
          <h1 className="text-lg font-semibold text-white">Panel de Administración</h1>
          <div className="flex items-center gap-4">
            <Link href="/" className="text-sm text-gray-400 hover:text-green-400">Ver sitio</Link>
            <button onClick={async () => { await supabase.auth.signOut(); window.location.href = "/login" }} className="text-sm text-red-400 hover:text-red-300">Salir</button>
          </div>
        </header>
        <main className="flex-1 p-6">{children}</main>
      </div>
    </div>
  )
}
